def is_prime(n, divisor=0):
    if divisor == 0:
        divisor = n - 1
    if n <= 1:
        return False
    if divisor == 1:
        return True
    if n % divisor == 0:
        return False
    return is_prime(n, divisor - 1)

n = int(input())
if is_prime(n):
    print("Yes")
else:
    print("No")
